// Get all items from Merge (Extract is index 0, Analysis is index 1)
const allItems = $input.all();

// Extract data from first item
const extractItem = allItems[0]?.json || {};
const docData = extractItem.data || extractItem;

// Analysis data from second item
const analysisItem = allItems[1]?.json || {};
const gapAnalysis = analysisItem.markdown || analysisItem.answer || analysisItem.text || 'No analysis generated';

// Get trigger data for file info
const triggerData = $('New Compliance Doc').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Count safeguards
const adminSafeguards = docData.administrativeSafeguards || [];
const physicalSafeguards = docData.physicalSafeguards || [];
const technicalSafeguards = docData.technicalSafeguards || [];

const totalSafeguards = adminSafeguards.length + physicalSafeguards.length + technicalSafeguards.length;
const implementedCount = [
  ...adminSafeguards.filter(s => s.implemented),
  ...physicalSafeguards.filter(s => s.implemented),
  ...technicalSafeguards.filter(s => s.implemented)
].length;

// Determine risk level based on gap analysis content
let riskLevel = 'Low';
let criticalCount = 0;
let highCount = 0;

const analysisLower = gapAnalysis.toLowerCase();
if (analysisLower.includes('critical')) {
  criticalCount = (analysisLower.match(/critical/g) || []).length;
}
if (analysisLower.includes('high')) {
  highCount = (analysisLower.match(/high/g) || []).length;
}

if (criticalCount >= 2) riskLevel = 'Critical';
else if (criticalCount >= 1 || highCount >= 3) riskLevel = 'High';
else if (highCount >= 1) riskLevel = 'Medium';

// Calculate compliance score
const complianceScore = totalSafeguards > 0 ? Math.round((implementedCount / totalSafeguards) * 100) : 0;

return [{
  json: {
    documentType: docData.documentType || 'Unknown',
    organizationName: docData.organizationName || 'Unknown',
    documentDate: docData.documentDate || 'N/A',
    versionNumber: docData.versionNumber || 'N/A',
    lastReviewDate: docData.lastReviewDate || 'N/A',
    nextReviewDate: docData.nextReviewDate || 'N/A',
    adminSafeguardsCount: adminSafeguards.length,
    physicalSafeguardsCount: physicalSafeguards.length,
    technicalSafeguardsCount: technicalSafeguards.length,
    totalSafeguards: totalSafeguards,
    implementedSafeguards: implementedCount,
    gapAnalysis: gapAnalysis,
    riskLevel: riskLevel,
    criticalIssues: criticalCount,
    highIssues: highCount,
    complianceScore: complianceScore,
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

